import java.io.*;
import java.util.*;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Sanitize and escape user input to prevent XSS
        name = sanitizeInput(name);

        // Output sanitized input within HTML element
        System.out.println("<div>Welcome, " + name + "!</div>");
    }

    private static String sanitizeInput(String input) {
        // Replace special characters that can be used for XSS with their HTML entity equivalents
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
